import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class NetworkQualityBar extends StatelessWidget { final double quality; const NetworkQualityBar({super.key, required this.quality}); @override Widget build(BuildContext context) { final c = quality > 0.7 ? AppTheme.successColor : quality > 0.4 ? AppTheme.warningColor : AppTheme.errorColor; return Column(mainAxisSize: MainAxisSize.min, children: [Row(mainAxisSize: MainAxisSize.min, children: List.generate(4, (i) { final active = quality >= (i + 1) * 0.25; return Container(width: 4, height: 6.0 + i * 3, margin: const EdgeInsets.only(right: 2), decoration: BoxDecoration(color: active ? c : AppTheme.darkBorder, borderRadius: BorderRadius.circular(2))); })), const SizedBox(height: 2), Text(quality > 0.7 ? 'Good' : quality > 0.4 ? 'Fair' : 'Poor', style: TextStyle(color: c, fontSize: 9, fontWeight: FontWeight.w700))]); } }